from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Start with the main subject
    main_subject = list(subject_map.keys())[0] if subject_map else ""
    sentence = main_subject

    # Use a single list for all clauses to allow natural ordering
    clauses = []

    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if predicate == "cityServed":
                clauses.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                clauses.append(f"has a mayor named {obj}")
            elif predicate == "isPartOf":
                clauses.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                clauses.append(f"is operated by {obj}")
            elif predicate == "location":
                clauses.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                clauses.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                clauses.append(f"has a runway that is {obj} metres long")
            elif predicate == "country":
                clauses.append(f"is located in {obj}")
            elif predicate == "capital":
                clauses.append(f"has {obj} as its capital")
            elif predicate == "language":
                clauses.append(f"where {obj} is spoken")
            elif predicate == "leader":
                clauses.append(f"has {obj} as its leader")
            elif predicate == "owner":
                clauses.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                clauses.append(f"has a first runway that is {obj} feet long")
            elif predicate == "1stRunwaySurfaceType":
                clauses.append(f"has a first runway with surface type {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                clauses.append(f"has a third runway that is {obj} feet long")
            elif predicate == "icaoLocationIdentifier":
                clauses.append(f"has an ICAO identifier of {obj}")
            elif predicate == "locationIdentifier":
                clauses.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                clauses.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                clauses.append(f"has an IATA identifier of {obj}")
            elif predicate == "nativeName":
                clauses.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                clauses.append(f"has a leader party of {obj}")
            else:
                # General case: improve readability by normalizing predicate names
                # Only if it's a known compound term; otherwise use as-is
                normalized = predicate
                if normalized.startswith("1stRunway"):
                    normalized = "first runway" + normalized[9:]
                elif normalized.startswith("3rdRunway"):
                    normalized = "third runway" + normalized[9:]
                elif normalized == "icaoLocationIdentifier":
                    normalized = "ICAO identifier"
                elif normalized == "iataLocationIdentifier":
                    normalized = "IATA identifier"
                elif normalized == "elevationAboveTheSeaLevel":
                    normalized = "elevation"
                elif normalized == "elevationAboveTheSeaLevelInFeet":
                    normalized = "elevation"
                elif normalized == "locationIdentifier":
                    normalized = "location identifier"
                clauses.append(f"has a {normalized} of {obj}")

    # Build sentence from all clauses
    if clauses:
        sentence += " " + ", ".join(clauses[:-1]) + (" and " + clauses[-1] if len(clauses) > 1 else clauses[-1])

    return sentence + "."

